// FizzBuzz — አማርኛ
// መለያዎች በአማርኛ። ኦፕሬተሮች ሁልጊዜ ምሳሌያዊ።

>> "ሰላም፣ አማርኛ ተናጋሪ ዓለም!" ¶

ምደባ(ቁጥር) {
    ? ቁጥር % 15 == 0 { <~ "ቡርቡርዝምዝም" }
    _? ቁጥር % 3  == 0 { <~ "ቡርቡር" }
    _? ቁጥር % 5  == 0 { <~ "ዝምዝም" }
    _ { <~ ቁጥር }
}

@ i:1..15 {
    >> ምደባ(i) ¶
}

// FizzBuzz — العربية
// المعرّفات بالعربية. المشغّلات دائماً رمزية.

>> "مرحباً، عالم ناطق بالعربية!" ¶

تصنيف(عدد) {
    ? عدد % 15 == 0 { <~ "فقاعةطنين" }
    _? عدد % 3  == 0 { <~ "فقاعة" }
    _? عدد % 5  == 0 { <~ "طنين" }
    _ { <~ عدد }
}

@ i:1..15 {
    >> تصنيف(i) ¶
}

// FizzBuzz — Български
// Идентификатори на Български. Операторите са винаги символни.

>> "Здравей, Български свят!" ¶

класификация(число) {
    ? число % 15 == 0 { <~ "СъскаБръм" }
    _? число % 3  == 0 { <~ "Съска" }
    _? число % 5  == 0 { <~ "Бръм" }
    _ { <~ число }
}

@ i:1..15 {
    >> класификация(i) ¶
}

