    ? broj % 15 == 0 { <~ "ŠišZuj" }
    _? broj % 3  == 0 { <~ "Šiš" }
    _? broj % 5  == 0 { <~ "Zuj" }
    _ { <~ broj }
}

@ i:1..15 {
    >> klasificiraj(i) ¶
}

