// FizzBuzz — اردو
// شناخت کنندے اردو میں۔ آپریٹر ہمیشہ علامتی۔

>> "ہیلو، اردو بولنے والی دنیا!" ¶

درجہبندی(عدد) {
    ? عدد % 15 == 0 { <~ "بلبلہبھن" }
    _? عدد % 3  == 0 { <~ "بلبلہ" }
    _? عدد % 5  == 0 { <~ "بھن" }
    _ { <~ عدد }
}

@ i:1..15 {
    >> درجہبندی(i) ¶
}

// FizzBuzz — Tiếng Việt
// Định danh bằng tiếng Việt. Toán tử luôn mang tính biểu tượng.

>> "Xin chào, Thế giới nói Tiếng Việt!" ¶

phânLoại(số) {
    ? số % 15 == 0 { <~ "XìVù" }
    _? số % 3  == 0 { <~ "Xì" }
    _? số % 5  == 0 { <~ "Vù" }
    _ { <~ số }
}

@ i:1..15 {
    >> phânLoại(i) ¶
}

// FizzBuzz — Yorùbá
// Awọn idanimọ ni Yorùbá. Awọn oniṣẹ jẹ aami nigbagbogbo.

>> "Ẹ káàbọ̀, Àgbáyé tó ń sọ Yorùbá!" ¶

ìpín(iye) {
    ? iye % 15 == 0 { <~ "FọnGún" }
    _? iye % 3  == 0 { <~ "Fọn" }
    _? iye % 5  == 0 { <~ "Gún" }
    _ { <~ iye }
}

@ i:1..15 {
    >> ìpín(i) ¶
}
